-- =============================
-- 3. Ensure night column exists
-- =============================
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 
        FROM information_schema.columns 
        WHERE table_name = 'edge_walkability_scores'
        AND column_name = 'base_night_safety_cost'
    ) THEN
        ALTER TABLE edge_walkability_scores
        ADD COLUMN base_night_safety_cost DOUBLE PRECISION;
    END IF;
END $$;

-- =============================
-- 4. Randomize NON-manual edges in envelope
-- =============================
UPDATE edge_walkability_scores s
SET 
    sidewalk_quality = vals.sidewalk,
    lighting_density = vals.lighting,
    business_activity = vals.business
FROM ways w,
LATERAL (
    SELECT 
        FLOOR(2 + RANDOM() * 3) AS sidewalk,
        FLOOR(RANDOM() * 3) AS lighting,
        FLOOR(RANDOM() * 3) AS business
) vals
WHERE w.id = s.edge_id
  AND w.geom && ST_MakeEnvelope(-84.3895, 33.7710, -84.3815, 33.7820, 4326)
  AND NOT EXISTS (
      SELECT 1 FROM manual_edges m WHERE m.edge_id = s.edge_id
  );

-- =============================
-- 5. Compute base_safety_cost
-- =============================
UPDATE edge_walkability_scores s
SET base_safety_cost =
    6 * (5 - s.sidewalk_quality) +
    1 * (2 - s.lighting_density) +
    3 * (2 - s.business_activity)
FROM ways w
WHERE w.id = s.edge_id
  AND w.geom && ST_MakeEnvelope(-84.3895, 33.7710, -84.3815, 33.7820, 4326);

-- =============================
-- 6. Compute base_night_safety_cost
-- =============================
UPDATE edge_walkability_scores s
SET base_night_safety_cost =
    2 * (5 - s.sidewalk_quality) +
    5 * (2 - s.lighting_density) +
    3 * (2 - s.business_activity)
FROM ways w
WHERE w.id = s.edge_id
  AND w.geom && ST_MakeEnvelope(-84.3895, 33.7710, -84.3815, 33.7820, 4326);

-- =============================
-- 7. Sanity check
-- =============================
SELECT 
    COUNT(*) AS total_edges_updated
FROM edge_walkability_scores s
JOIN ways w ON w.id = s.edge_id
WHERE w.geom && ST_MakeEnvelope(-84.3895, 33.7710, -84.3815, 33.7820, 4326);